/**
 * HTTP Client with automatic token management
 */

import type { PayCanConfig, ApiError } from './types';

export class HttpClient {
  private config: PayCanConfig;
  private token: string | null = null;
  private tokenExpiry: number | null = null;
  private refreshPromise: Promise<void> | null = null;

  constructor(config: PayCanConfig) {
    this.config = config;
  }

  /**
   * Set the authentication token
   */
  setToken(token: string): void {
    this.token = token;
    this.tokenExpiry = this.parseTokenExpiry(token);
    this.log('Token set, expires at:', new Date(this.tokenExpiry || 0).toISOString());
  }

  /**
   * Get current token
   */
  getToken(): string | null {
    return this.token;
  }

  /**
   * Check if token needs refresh
   */
  private needsRefresh(): boolean {
    if (!this.tokenExpiry) return false;

    const threshold = (this.config.refreshThreshold || 300) * 1000; // Convert to ms
    const now = Date.now();
    const timeUntilExpiry = this.tokenExpiry - now;

    return timeUntilExpiry <= threshold;
  }

  /**
   * Parse JWT token to get expiry time
   */
  private parseTokenExpiry(token: string): number | null {
    try {
      const payload = token.split('.')[1];
      const decoded = JSON.parse(atob(payload));
      return decoded.exp ? decoded.exp * 1000 : null; // Convert to ms
    } catch (error) {
      this.log('Failed to parse token expiry:', error);
      return null;
    }
  }

  /**
   * Make HTTP request with automatic token refresh
   */
  async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    await this.ensureValidToken();

    const url = `${this.config.apiUrl}${endpoint}`;
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      ...(options.headers as Record<string, string> || {}),
    };

    if (this.token) {
      headers['Authorization'] = `Bearer ${this.token}`;
    }

    this.log(`${options.method || 'GET'} ${url}`);

    const response = await fetch(url, {
      ...options,
      headers,
    });

    return this.handleResponse<T>(response);
  }

  /**
   * Ensure we have a valid token, refresh if needed
   */
  private async ensureValidToken(): Promise<void> {
    if (!this.token) {
      throw new Error('Not authenticated. Please call setUser() first.');
    }

    if (this.needsRefresh()) {
      // If refresh is already in progress, wait for it
      if (this.refreshPromise) {
        await this.refreshPromise;
        return;
      }

      // Start refresh
      this.refreshPromise = this.refreshToken();
      await this.refreshPromise;
      this.refreshPromise = null;
    }
  }

  /**
   * Refresh the authentication token
   * This is called automatically when token is close to expiry
   */
  private async refreshToken(): Promise<void> {
    this.log('Refreshing token...');

    // Token refresh happens through the auth endpoint
    // The backend should handle token refresh logic
    // For now, we'll rely on the token's expiry time
    // If you implement a refresh endpoint, call it here
  }

  /**
   * Handle HTTP response
   */
  private async handleResponse<T>(response: Response): Promise<T> {
    const contentType = response.headers.get('content-type');
    const isJson = contentType?.includes('application/json');

    if (!response.ok) {
      let error: ApiError = {
        message: response.statusText,
        status: response.status,
      };

      if (isJson) {
        try {
          const errorData = await response.json();
          error = {
            message: errorData.message || error.message,
            errors: errorData.errors,
            status: response.status,
          };
        } catch (e) {
          // Use default error if JSON parsing fails
        }
      }

      this.log('API Error:', error);
      throw error;
    }

    if (isJson) {
      return response.json();
    }

    return {} as T;
  }

  /**
   * Debug logging
   */
  private log(...args: any[]): void {
    if (this.config.debug) {
      console.log('[PayCan SDK]', ...args);
    }
  }

  /**
   * GET request
   */
  async get<T>(endpoint: string, params?: Record<string, any>): Promise<T> {
    let url = endpoint;
    if (params) {
      const queryString = new URLSearchParams(
        Object.entries(params).reduce((acc, [key, value]) => {
          if (value !== undefined && value !== null) {
            acc[key] = String(value);
          }
          return acc;
        }, {} as Record<string, string>)
      ).toString();
      if (queryString) {
        url = `${endpoint}?${queryString}`;
      }
    }
    return this.request<T>(url, { method: 'GET' });
  }

  /**
   * POST request
   */
  async post<T>(endpoint: string, data?: any): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'POST',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  /**
   * PUT request
   */
  async put<T>(endpoint: string, data?: any): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'PUT',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  /**
   * DELETE request
   */
  async delete<T>(endpoint: string): Promise<T> {
    return this.request<T>(endpoint, { method: 'DELETE' });
  }
}
