/**
 * PayCan Checkout Modal Web Component
 *
 * A framework-agnostic checkout modal that can be embedded anywhere
 */

import type { PayCan } from '../paycan';
import type { CheckoutPreviewResponse, CheckoutPreviewPrice } from '../types';

export interface CheckoutModalOptions {
  productId?: number;
  priceId?: number;
  theme?: 'light' | 'dark';
  onSuccess?: (checkoutUrl: string) => void;
  onCancel?: () => void;
  onError?: (error: Error) => void;
}

export class CheckoutModal {
  private sdk: PayCan;
  private options: CheckoutModalOptions;
  private overlay: HTMLElement | null = null;
  private modal: HTMLElement | null = null;
  private previewData: CheckoutPreviewResponse | null = null;
  private selectedPriceId: number | null = null;
  private selectedGateway: string = 'stripe';
  private loading: boolean = false;

  constructor(sdk: PayCan, options: CheckoutModalOptions) {
    this.sdk = sdk;
    this.options = options;
    this.selectedPriceId = options.priceId || null;
  }

  /**
   * Open the modal and load preview data
   */
  async open(): Promise<void> {
    try {
      // Load preview data
      await this.loadPreview();

      // Create and show modal
      this.createModal();
      this.show();
    } catch (error) {
      this.handleError(error as Error);
    }
  }

  /**
   * Close and destroy the modal
   */
  close(): void {
    if (this.overlay) {
      this.overlay.remove();
      this.overlay = null;
      this.modal = null;
    }
    if (this.options.onCancel) {
      this.options.onCancel();
    }
  }

  /**
   * Load preview data from API
   */
  private async loadPreview(): Promise<void> {
    const params: any = {
      quantity: 1,
    };

    if (this.options.productId) {
      params.product_id = this.options.productId;
      if (this.selectedPriceId) {
        params.selected_price_id = this.selectedPriceId;
      }
    } else if (this.selectedPriceId) {
      params.product_price_id = this.selectedPriceId;
    }

    this.previewData = await this.sdk.checkout.preview(params);

    // Set default selected price if not set
    if (!this.selectedPriceId && this.previewData.selected_price) {
      this.selectedPriceId = this.previewData.selected_price.id;
    }

    // Set default gateway from available payment methods
    if (this.previewData.payment_methods.length > 0) {
      this.selectedGateway = this.previewData.payment_methods[0].key;
    }
  }

  /**
   * Create modal DOM structure
   */
  private createModal(): void {
    const theme = this.options.theme || 'light';

    // Create overlay
    this.overlay = document.createElement('div');
    this.overlay.className = `paycan-modal-overlay paycan-theme-${theme}`;
    this.overlay.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.5);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 999999;
      padding: 1rem;
      opacity: 0;
      transition: opacity 0.2s ease-in-out;
    `;

    // Create modal container
    this.modal = document.createElement('div');
    this.modal.className = 'paycan-modal';
    this.modal.style.cssText = `
      background: ${theme === 'dark' ? '#1f2937' : '#ffffff'};
      border-radius: 12px;
      box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
      max-width: 500px;
      width: 100%;
      max-height: 90vh;
      overflow-y: auto;
      color: ${theme === 'dark' ? '#f9fafb' : '#111827'};
      transform: scale(0.95);
      transition: transform 0.2s ease-in-out;
    `;

    this.modal.innerHTML = this.getModalContent();

    this.overlay.appendChild(this.modal);
    document.body.appendChild(this.overlay);

    // Add event listeners
    this.attachEventListeners();

    // Close on overlay click
    this.overlay.addEventListener('click', (e) => {
      if (e.target === this.overlay) {
        this.close();
      }
    });

    // Close on Escape key
    document.addEventListener('keydown', this.handleEscapeKey);
  }

  /**
   * Get modal HTML content
   */
  private getModalContent(): string {
    if (!this.previewData) {
      return '<div style="padding: 2rem; text-align: center;">Loading...</div>';
    }

    const theme = this.options.theme || 'light';
    const isDark = theme === 'dark';
    const isAuthenticated = this.sdk.isAuthenticated();

    const product = this.previewData.product;
    const selectedPrice = this.previewData.selected_price;
    const prices = this.previewData.prices;
    const paymentMethods = this.previewData.payment_methods;

    return `
      <div style="padding: 1.5rem;">
        <!-- Header -->
        <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 1.5rem;">
          <h2 style="font-size: 1.5rem; font-weight: 700; margin: 0; color: ${isDark ? '#f9fafb' : '#111827'};">
            🛒 Checkout
          </h2>
          <button
            class="paycan-close-btn"
            style="background: none; border: none; font-size: 1.5rem; cursor: pointer; padding: 0; color: ${isDark ? '#9ca3af' : '#6b7280'}; line-height: 1;"
            aria-label="Close"
          >
            ×
          </button>
        </div>

        <!-- Product Info -->
        <div style="background: ${isDark ? '#374151' : '#f9fafb'}; border: 1px solid ${isDark ? '#4b5563' : '#e5e7eb'}; border-radius: 8px; padding: 1rem; margin-bottom: 1.5rem;">
          <h3 style="font-size: 1.125rem; font-weight: 600; margin: 0 0 0.5rem 0; color: ${isDark ? '#f9fafb' : '#111827'};">
            ${this.escapeHtml(product.name)}
          </h3>
          ${product.description ? `<p style="font-size: 0.875rem; color: ${isDark ? '#d1d5db' : '#6b7280'}; margin: 0;">${this.escapeHtml(product.description)}</p>` : ''}
          <div style="margin-top: 0.75rem;">
            <span style="display: inline-block; background: ${this.getProductTypeBg(product.type, isDark)}; color: ${this.getProductTypeColor(product.type, isDark)}; padding: 0.25rem 0.75rem; border-radius: 9999px; font-size: 0.75rem; font-weight: 500;">
              ${this.escapeHtml(product.type)}
            </span>
          </div>
        </div>

        ${!isAuthenticated ? this.getGuestEmailField(isDark) : ''}

        ${prices.length > 1 ? this.getPriceSelectionField(prices, isDark) : ''}

        ${selectedPrice ? this.getPriceBreakdown(selectedPrice, isDark) : ''}

        ${paymentMethods.length > 0 ? this.getPaymentMethodsField(paymentMethods, isDark) : ''}

        <!-- Security Notice -->
        <div style="background: ${isDark ? '#1f2937' : '#f9fafb'}; border: 1px solid ${isDark ? '#374151' : '#e5e7eb'}; border-radius: 6px; padding: 0.75rem; margin-bottom: 1.5rem;">
          <p style="font-size: 0.75rem; color: ${isDark ? '#9ca3af' : '#6b7280'}; margin: 0;">
            🔒 Your payment information is secure and encrypted. We never store your card details.
          </p>
        </div>

        <!-- Actions -->
        <div style="display: flex; gap: 0.75rem; justify-content: flex-end;">
          <button
            class="paycan-cancel-btn"
            style="background: ${isDark ? '#374151' : '#ffffff'}; color: ${isDark ? '#f9fafb' : '#111827'}; border: 1px solid ${isDark ? '#4b5563' : '#d1d5db'}; padding: 0.625rem 1.25rem; border-radius: 6px; font-size: 0.875rem; font-weight: 500; cursor: pointer; transition: all 0.15s;"
          >
            Cancel
          </button>
          <button
            class="paycan-checkout-btn"
            style="background: #3b82f6; color: white; border: none; padding: 0.625rem 1.5rem; border-radius: 6px; font-size: 0.875rem; font-weight: 500; cursor: pointer; transition: all 0.15s;"
            ${this.loading ? 'disabled' : ''}
          >
            ${this.loading ? 'Processing...' : selectedPrice ? `Pay ${this.formatPrice(selectedPrice.final_price, selectedPrice.currency)}` : 'Continue'}
          </button>
        </div>
      </div>
    `;
  }

  /**
   * Get guest email field HTML
   */
  private getGuestEmailField(isDark: boolean): string {
    return `
      <div style="margin-bottom: 1.5rem;">
        <label style="display: block; font-size: 0.875rem; font-weight: 500; margin-bottom: 0.5rem; color: ${isDark ? '#f9fafb' : '#111827'};">
          Email Address <span style="color: #ef4444;">*</span>
        </label>
        <input
          type="email"
          class="paycan-email-input"
          placeholder="your@email.com"
          required
          style="width: 100%; padding: 0.625rem; border: 1px solid ${isDark ? '#4b5563' : '#d1d5db'}; border-radius: 6px; font-size: 0.875rem; background: ${isDark ? '#374151' : '#ffffff'}; color: ${isDark ? '#f9fafb' : '#111827'}; box-sizing: border-box;"
        />
        <p style="font-size: 0.75rem; color: ${isDark ? '#9ca3af' : '#6b7280'}; margin: 0.375rem 0 0 0;">
          We'll send your receipt and purchase details to this email.
        </p>
      </div>
    `;
  }

  /**
   * Get price selection field HTML
   */
  private getPriceSelectionField(prices: CheckoutPreviewPrice[], isDark: boolean): string {
    if (prices.length < 3) {
      // Radio buttons
      return `
        <div style="margin-bottom: 1.5rem;">
          <label style="display: block; font-size: 0.875rem; font-weight: 500; margin-bottom: 0.75rem; color: ${isDark ? '#f9fafb' : '#111827'};">
            Select Plan
          </label>
          <div style="display: flex; flex-direction: column; gap: 0.75rem;">
            ${prices.map(price => `
              <label style="display: flex; align-items: center; padding: 1rem; border: 2px solid ${this.selectedPriceId === price.id ? '#3b82f6' : (isDark ? '#4b5563' : '#e5e7eb')}; background: ${this.selectedPriceId === price.id ? (isDark ? '#1e3a8a' : '#eff6ff') : (isDark ? '#374151' : '#ffffff')}; border-radius: 8px; cursor: pointer; transition: all 0.15s;">
                <input
                  type="radio"
                  name="price"
                  value="${price.id}"
                  class="paycan-price-radio"
                  ${this.selectedPriceId === price.id ? 'checked' : ''}
                  style="margin-right: 0.75rem;"
                />
                <div style="flex: 1;">
                  <div style="display: flex; justify-content: space-between; align-items: center;">
                    <span style="font-weight: 600; color: ${isDark ? '#f9fafb' : '#111827'};">${this.escapeHtml(price.name)}</span>
                    <span style="font-weight: 700; font-size: 1.125rem; color: ${isDark ? '#f9fafb' : '#111827'};">${this.formatPrice(price.final_price, price.currency)}</span>
                  </div>
                  <div style="font-size: 0.75rem; color: ${isDark ? '#9ca3af' : '#6b7280'}; margin-top: 0.25rem;">
                    ${this.getBillingPeriodText(price.billing_period)}${price.trial_days ? ` • ${price.trial_days} days free trial` : ''}
                  </div>
                </div>
              </label>
            `).join('')}
          </div>
        </div>
      `;
    } else {
      // Dropdown
      return `
        <div style="margin-bottom: 1.5rem;">
          <label style="display: block; font-size: 0.875rem; font-weight: 500; margin-bottom: 0.5rem; color: ${isDark ? '#f9fafb' : '#111827'};">
            Select Plan
          </label>
          <select
            class="paycan-price-select"
            style="width: 100%; padding: 0.625rem; border: 1px solid ${isDark ? '#4b5563' : '#d1d5db'}; border-radius: 6px; font-size: 0.875rem; background: ${isDark ? '#374151' : '#ffffff'}; color: ${isDark ? '#f9fafb' : '#111827'}; cursor: pointer;"
          >
            ${prices.map(price => `
              <option value="${price.id}" ${this.selectedPriceId === price.id ? 'selected' : ''}>
                ${this.escapeHtml(price.name)} - ${this.formatPrice(price.final_price, price.currency)} ${this.getBillingPeriodText(price.billing_period)}
              </option>
            `).join('')}
          </select>
        </div>
      `;
    }
  }

  /**
   * Get price breakdown HTML
   */
  private getPriceBreakdown(price: CheckoutPreviewPrice, isDark: boolean): string {
    return `
      <div style="background: ${isDark ? '#111827' : '#f9fafb'}; border: 1px solid ${isDark ? '#374151' : '#e5e7eb'}; border-radius: 8px; padding: 1rem; margin-bottom: 1.5rem;">
        <div style="display: flex; justify-content: space-between; margin-bottom: 0.5rem;">
          <span style="font-size: 0.875rem; color: ${isDark ? '#9ca3af' : '#6b7280'};">Subtotal</span>
          <span style="font-size: 0.875rem; font-weight: 500; color: ${isDark ? '#f9fafb' : '#111827'};">${this.formatPrice(price.subtotal, price.currency)}</span>
        </div>
        ${price.tax_amount > 0 ? `
          <div style="display: flex; justify-content: space-between; margin-bottom: 0.5rem;">
            <span style="font-size: 0.875rem; color: ${isDark ? '#9ca3af' : '#6b7280'};">Tax (${(this.previewData!.tax.rate * 100).toFixed(1)}%)</span>
            <span style="font-size: 0.875rem; font-weight: 500; color: ${isDark ? '#f9fafb' : '#111827'};">${this.formatPrice(price.tax_amount, price.currency)}</span>
          </div>
        ` : ''}
        <div style="border-top: 1px solid ${isDark ? '#374151' : '#e5e7eb'}; margin: 0.75rem 0; padding-top: 0.75rem;"></div>
        <div style="display: flex; justify-content: space-between; align-items: center;">
          <span style="font-weight: 600; color: ${isDark ? '#f9fafb' : '#111827'};">Total</span>
          <div style="text-align: right;">
            <div style="font-size: 1.5rem; font-weight: 700; color: ${isDark ? '#f9fafb' : '#111827'};">${this.formatPrice(price.final_price, price.currency)}</div>
            <div style="font-size: 0.75rem; color: ${isDark ? '#9ca3af' : '#6b7280'};">${this.getBillingPeriodText(price.billing_period)}</div>
          </div>
        </div>
      </div>
    `;
  }

  /**
   * Get payment methods field HTML
   */
  private getPaymentMethodsField(methods: any[], isDark: boolean): string {
    return `
      <div style="margin-bottom: 1.5rem;">
        <label style="display: block; font-size: 0.875rem; font-weight: 500; margin-bottom: 0.75rem; color: ${isDark ? '#f9fafb' : '#111827'};">
          Payment Method
        </label>
        <div style="display: flex; flex-direction: column; gap: 0.75rem;">
          ${methods.map(method => `
            <label style="display: flex; align-items: center; padding: 1rem; border: 2px solid ${this.selectedGateway === method.key ? '#3b82f6' : (isDark ? '#4b5563' : '#e5e7eb')}; background: ${this.selectedGateway === method.key ? (isDark ? '#1e3a8a' : '#eff6ff') : (isDark ? '#374151' : '#ffffff')}; border-radius: 8px; cursor: pointer; transition: all 0.15s;">
              <input
                type="radio"
                name="gateway"
                value="${method.key}"
                class="paycan-gateway-radio"
                ${this.selectedGateway === method.key ? 'checked' : ''}
                style="margin-right: 0.75rem;"
              />
              <div style="flex: 1;">
                <div style="font-weight: 600; color: ${isDark ? '#f9fafb' : '#111827'}; margin-bottom: 0.25rem;">${this.escapeHtml(method.name)}</div>
                ${method.description ? `<div style="font-size: 0.75rem; color: ${isDark ? '#9ca3af' : '#6b7280'};">${this.escapeHtml(method.description)}</div>` : ''}
              </div>
              ${method.supports_subscriptions ? '<span style="font-size: 0.625rem; background: #10b981; color: white; padding: 0.125rem 0.5rem; border-radius: 9999px; font-weight: 500;">Subscriptions</span>' : ''}
            </label>
          `).join('')}
        </div>
      </div>
    `;
  }

  /**
   * Attach event listeners to modal elements
   */
  private attachEventListeners(): void {
    if (!this.modal) return;

    // Close button
    const closeBtn = this.modal.querySelector('.paycan-close-btn');
    closeBtn?.addEventListener('click', () => this.close());

    // Cancel button
    const cancelBtn = this.modal.querySelector('.paycan-cancel-btn');
    cancelBtn?.addEventListener('click', () => this.close());

    // Checkout button
    const checkoutBtn = this.modal.querySelector('.paycan-checkout-btn');
    checkoutBtn?.addEventListener('click', () => this.handleCheckout());

    // Price radio buttons
    const priceRadios = this.modal.querySelectorAll('.paycan-price-radio');
    priceRadios.forEach(radio => {
      radio.addEventListener('change', (e) => {
        const target = e.target as HTMLInputElement;
        this.handlePriceChange(parseInt(target.value));
      });
    });

    // Price dropdown
    const priceSelect = this.modal.querySelector('.paycan-price-select') as HTMLSelectElement;
    priceSelect?.addEventListener('change', (e) => {
      const target = e.target as HTMLSelectElement;
      this.handlePriceChange(parseInt(target.value));
    });

    // Gateway radio buttons
    const gatewayRadios = this.modal.querySelectorAll('.paycan-gateway-radio');
    gatewayRadios.forEach(radio => {
      radio.addEventListener('change', (e) => {
        const target = e.target as HTMLInputElement;
        this.selectedGateway = target.value;
      });
    });
  }

  /**
   * Handle price change
   */
  private async handlePriceChange(priceId: number): Promise<void> {
    this.selectedPriceId = priceId;
    try {
      // Reload preview with new price
      await this.loadPreview();
      // Re-render modal
      if (this.modal) {
        this.modal.innerHTML = this.getModalContent();
        this.attachEventListeners();
      }
    } catch (error) {
      this.handleError(error as Error);
    }
  }

  /**
   * Handle checkout button click
   */
  private async handleCheckout(): Promise<void> {
    if (this.loading) return;

    try {
      this.loading = true;
      this.updateCheckoutButton();

      // Validate email if guest
      let billingEmail: string | undefined;
      if (!this.sdk.isAuthenticated()) {
        const emailInput = this.modal?.querySelector('.paycan-email-input') as HTMLInputElement;
        if (!emailInput || !emailInput.value || !this.isValidEmail(emailInput.value)) {
          throw new Error('Please enter a valid email address');
        }
        billingEmail = emailInput.value;
      }

      // Create checkout session
      const checkoutData: any = {
        product_price_id: this.selectedPriceId!,
        gateway: this.selectedGateway,
        quantity: 1,
      };

      if (this.previewData) {
        checkoutData.product_id = this.previewData.product.id;
      }

      if (billingEmail) {
        checkoutData.billing_email = billingEmail;
      }

      const session = await this.sdk.checkout.create(checkoutData);

      // Call success callback or redirect
      if (this.options.onSuccess) {
        this.options.onSuccess(session.checkout_url);
      } else {
        window.location.href = session.checkout_url;
      }

      this.close();
    } catch (error) {
      this.loading = false;
      this.updateCheckoutButton();
      this.handleError(error as Error);
    }
  }

  /**
   * Update checkout button state
   */
  private updateCheckoutButton(): void {
    const btn = this.modal?.querySelector('.paycan-checkout-btn') as HTMLButtonElement;
    if (btn) {
      btn.disabled = this.loading;
      btn.textContent = this.loading ? 'Processing...' :
        this.previewData?.selected_price ?
          `Pay ${this.formatPrice(this.previewData.selected_price.final_price, this.previewData.selected_price.currency)}` :
          'Continue';
    }
  }

  /**
   * Handle escape key press
   */
  private handleEscapeKey = (e: KeyboardEvent): void => {
    if (e.key === 'Escape') {
      this.close();
    }
  };

  /**
   * Show modal with animation
   */
  private show(): void {
    if (this.overlay && this.modal) {
      // Trigger reflow for animation
      this.overlay.offsetHeight;
      this.overlay.style.opacity = '1';
      this.modal.style.transform = 'scale(1)';
    }
  }

  /**
   * Handle errors
   */
  private handleError(error: Error): void {
    console.error('[PayCan Checkout Modal]', error);
    if (this.options.onError) {
      this.options.onError(error);
    } else {
      alert(`Checkout Error: ${error.message}`);
    }
  }

  /**
   * Format price
   */
  private formatPrice(amount: number, currency: string): string {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: currency || 'USD',
    }).format(amount);
  }

  /**
   * Get billing period text
   */
  private getBillingPeriodText(period: string): string {
    if (period === 'once') return 'one-time payment';
    return `per ${period}`;
  }

  /**
   * Get product type background color
   */
  private getProductTypeBg(type: string, isDark: boolean): string {
    const colors: Record<string, string> = {
      digital: isDark ? '#1e3a8a' : '#dbeafe',
      physical: isDark ? '#065f46' : '#d1fae5',
      service: isDark ? '#581c87' : '#f3e8ff',
      subscription: isDark ? '#9a3412' : '#fed7aa',
    };
    return colors[type] || (isDark ? '#374151' : '#f3f4f6');
  }

  /**
   * Get product type text color
   */
  private getProductTypeColor(type: string, isDark: boolean): string {
    const colors: Record<string, string> = {
      digital: isDark ? '#93c5fd' : '#1e40af',
      physical: isDark ? '#6ee7b7' : '#047857',
      service: isDark ? '#d8b4fe' : '#6b21a8',
      subscription: isDark ? '#fdba74' : '#c2410c',
    };
    return colors[type] || (isDark ? '#d1d5db' : '#4b5563');
  }

  /**
   * Validate email
   */
  private isValidEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }

  /**
   * Escape HTML to prevent XSS
   */
  private escapeHtml(text: string): string {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }

  /**
   * Cleanup
   */
  destroy(): void {
    document.removeEventListener('keydown', this.handleEscapeKey);
    this.close();
  }
}
